import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Dashboard Reports","description":"","frontmatter":{"title":"Dashboard Reports","slug":"dashboard-reports"},"headers":[],"relativePath":"marketer-hub/dashboard-reports.md","filePath":"marketer-hub/dashboard-reports.md"}'),i={name:"marketer-hub/dashboard-reports.md"};function n(l,e,s,h,d,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a> is the best place to view your campaign performance across all of your Branch-integrated channels. Use the data collected through Branch&#39;s cross-platform Link Graph to make data-driven decisions to improve metrics and user experience.</p><h3 id="available-reports" tabindex="-1">Available Reports: <a class="header-anchor" href="#available-reports" aria-label="Permalink to &quot;Available Reports:&quot;">​</a></h3><ul><li><p><a href="./branch-summary-page.html">Summary</a></p></li><li><p><a href="./universal-ads-reporting.html">Ads</a></p><ul><li><a href="./skadnetwork-dashboard-reports.html">SKAdNetwork</a></li></ul></li><li><p><a href="./journeys-analytics.html">Journeys</a></p></li><li><p>Email</p></li><li><p>Short Links</p></li><li><p>Sources</p></li></ul><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Limitation</th><th>Details</th></tr></thead><tbody><tr><td>Max lookback</td><td>6 months</td></tr></tbody></table><h3 id="filter-bar" tabindex="-1">Filter Bar <a class="header-anchor" href="#filter-bar" aria-label="Permalink to &quot;Filter Bar&quot;">​</a></h3><p>The Filter Bar allows you to add multiple controls across your charts and tables. With it, you&#39;ll be able to control the following:</p><ul><li>Date Range</li><li>Apply Filters</li><li>Saving Views</li><li>Sharing Views</li><li>Reset View</li></ul><h3 id="saving-views" tabindex="-1">Saving Views <a class="header-anchor" href="#saving-views" aria-label="Permalink to &quot;Saving Views&quot;">​</a></h3><p>You can also save the current state of your report - i.e. including whatever changes you have made to the default view - by clicking on the <strong>flag button</strong>, naming the view, and clicking <strong>Save</strong>.</p><p>You can also access your previously saved reports here as well.</p><h3 id="sharing-views" tabindex="-1">Sharing Views <a class="header-anchor" href="#sharing-views" aria-label="Permalink to &quot;Sharing Views&quot;">​</a></h3><p>You can easily share the current state of your report - i.e. including whatever changes you have made to the default view - by clicking on the <strong>link button</strong> and copying the auto-generated Branch Link. You can then send this link to users who have access to your Branch Dashboard for them to view that report.</p><h2 id="trends-graph" tabindex="-1">Trends Graph <a class="header-anchor" href="#trends-graph" aria-label="Permalink to &quot;Trends Graph&quot;">​</a></h2><p>The Trends Graph is a type of view in the Branch Dashboard that allows you to view your campaign performance through robust charts.</p><p>The Trends Graph can be customized to show <strong>two</strong> events compared by a specific attribute.</p><h4 id="filter" tabindex="-1">Filter <a class="header-anchor" href="#filter" aria-label="Permalink to &quot;Filter&quot;">​</a></h4><p>Applying filters can help drill down into more specific campaign parameters to better fit the story of your report. Filters uses a set of operators to specify those parameters:</p><ul><li>equals</li><li>contains</li><li>starts with</li><li>ends with<br> The available options you have for filters are based on what is currently available in your Branch data. If you don&#39;t see a specific option on your filter, it likely means that the data is not yet there or something went wrong during implementation.</li></ul><h4 id="granularity" tabindex="-1">Granularity <a class="header-anchor" href="#granularity" aria-label="Permalink to &quot;Granularity&quot;">​</a></h4><p>Granularity allows you to break down the chart by day, week, or month.</p><h2 id="events-performance-table" tabindex="-1">Events/Performance Table <a class="header-anchor" href="#events-performance-table" aria-label="Permalink to &quot;Events/Performance Table&quot;">​</a></h2><p>The Events/Performance Table is a type of view in the Branch Dashboard that allows you to view your campaign performance through customizable tables with download capabilities.</p><h4 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h4><p>To change which events and/or metrics are shown as columns:</p><ol><li>In the header of the table, in the far-right upper corner, click the three-column button.</li><li>Select the events and/or metrics of interest to you.</li><li>To re-arrange the column order, click on the dotted tab to the right of the column name and drag to re-order.</li></ol><p>Additionally, you have the ability to customize your columns even further through the Column Selector. With it you&#39;ll be able to have new sections:</p><ul><li><strong>Events</strong>: An ordered list of events.</li><li><strong>Metrics</strong>: All Branch pre-calculated metrics.</li><li><strong>Ordering</strong>: The ordering space for all selected columns including compare-by as well as selected events and metrics with easy drag-and-drop functionality.</li></ul><p>Events within each bucket are ordered by the volume received in the past 15 days. The most relevant events for each app will always appear at top of the list. You can also pin your favorite events and metrics to always appear on top.</p><p>Note: Any event with zero volume will appear at the bottom irrespective of the event type.</p><h4 id="adding-a-custom-metric" tabindex="-1">Adding a Custom Metric <a class="header-anchor" href="#adding-a-custom-metric" aria-label="Permalink to &quot;Adding a Custom Metric&quot;">​</a></h4><p>In the column selector, you can also make your own custom metrics for more insights from your aggregated data. Formulaic calculations between event counts and aggregations are supported. Additionally, you will have access to templated calculations like Average Order Value and Customer Acquisition Cost.</p><h4 id="compare-by" tabindex="-1">Compare By <a class="header-anchor" href="#compare-by" aria-label="Permalink to &quot;Compare By&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Limitation</p><p>Note: The following combination in the <strong>Compare by</strong> field will cause an error in loading data into the Events/Performance Table:</p><ul><li>OS + Country</li></ul><p><strong>OR</strong></p><ul><li>Secondary Publisher + Country</li></ul></div><p>To modify which dimension the columns are split by:</p><ol><li>Click on the <strong>Compare by</strong> drop-down and select the dimension on which you want the event split.</li><li>To remove a dimension, click the<strong>X</strong> next to the event in the <strong>Compare by</strong> field.</li></ol><h4 id="filter-1" tabindex="-1">Filter <a class="header-anchor" href="#filter-1" aria-label="Permalink to &quot;Filter&quot;">​</a></h4><p>Applying filters can help drill down into more specific campaign parameters to better fit the story of your report. Filters uses a set of operators to specify those parameters:</p><ul><li>equals</li><li>contains</li><li>starts with</li><li>ends with<br> The available options you have for filters are based on what is currently available in your Branch data. If you don&#39;t see a specific option on your filter, it likely means that the data is not yet there or something went wrong during implementation.</li></ul><h4 id="granularity-1" tabindex="-1">Granularity <a class="header-anchor" href="#granularity-1" aria-label="Permalink to &quot;Granularity&quot;">​</a></h4><p>Granularity allows you to break down the chart by day, week, month, or all time.</p><h4 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;Tags&quot;">​</a></h4><p>You can add <code>tags</code> to nearly everything you do with Branch. This includes Branch Links, Journeys, etc. You can add the <code>tags</code> to your Compare By to differentiate between the different uses of Branch, campaigns, and more!</p><h3 id="report-previews" tabindex="-1">Report Previews <a class="header-anchor" href="#report-previews" aria-label="Permalink to &quot;Report Previews&quot;">​</a></h3><p>If certain conditions are met, you may see a prompt on Events/Performance Tables to <strong>Run Full Report</strong>. To ensure stable performance and usability, Branch only shows you partial data for your report until you confirm to run the full report. This is also a good opportunity to confirm you have the correct columns/dimensions set.</p><p>Report Previews only initiate when the following conditions are met:</p><table tabindex="0"><thead><tr><th>Time-Range</th><th>Granularity</th><th>Preview Data Time Range</th></tr></thead><tbody><tr><td><code>&gt; 30 Days</code></td><td>Daily</td><td>First 7 Days</td></tr><tr><td><code>&gt; 60 Days</code></td><td>Weekly</td><td>First 2 Weeks</td></tr><tr><td><code>&gt; 90 Days</code></td><td>Monthly</td><td>First 1 Month</td></tr></tbody></table><h3 id="export-csv" tabindex="-1">Export CSV <a class="header-anchor" href="#export-csv" aria-label="Permalink to &quot;Export CSV&quot;">​</a></h3><p>In addition to seeing the report in the Events/Performance Tables, you also have the ability to export the table as a CSV by clicking the <strong>download</strong> button next to the granularity setting. The CSV you export will abide by the time range you set from the <strong>Export CSV</strong> modal.</p>',50)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
